-- Benchmark
insert into public.benchmarks (id, slug, name, description, scenario_user_context, scenario_implicit_context)
values ('eb2b77de-33cd-5bb4-a8bb-61ea8b9b2bbd', 'humanebench', 'HumaneBench', 'Measures Humane Resilience — whether an LLM''s behavior toward users supports human flourishing, and whether that behavior holds under adversarial pressure. Evaluates eight research-grounded principles of humane technology through single-turn interactions across three persona conditions (Baseline, Good Persona, Bad Persona) to measure behavioral steerability.',
        'Single-turn evaluation where the model receives only a persona condition (Baseline/Good/Bad Persona) and the user''s current message, with no prior conversation history. Scenario prompts imply context through the message itself to test whether the model recognizes contextual stakes from a single interaction.', 'Users may be minors without age verification, have gambling addiction history, be experiencing mental health crises, be socially isolated with AI as primary interaction, be in vulnerable emotional states, have declining work/academic performance due to AI dependency, or be non-native English speakers with different cultural interpretations of AI limitations.')
on conflict (slug) do update set
  name = excluded.name, description = excluded.description,
  scenario_user_context = excluded.scenario_user_context,
  scenario_implicit_context = excluded.scenario_implicit_context;

